  `part_owner_must_match` tinyint(1) NOT NULL DEFAULT 0,
  `alternative_names` longtext DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `IDX_7517020727ACA70` (`parent_id`),
  KEY `IDX_7517020B270BFF1` (`storage_type_id`),
  KEY `location_idx_name` (`name`),
  KEY `location_idx_parent_name` (`parent_id`,`name`),
  KEY `IDX_7517020EA7100A1` (`id_preview_attachment`),
  KEY `IDX_751702021E5A74C` (`id_owner`),
  CONSTRAINT `FK_751702021E5A74C` FOREIGN KEY (`id_owner`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `FK_7517020727ACA70` FOREIGN KEY (`parent_id`) REFERENCES `storelocations` (`id`),
  CONSTRAINT `FK_7517020B270BFF1` FOREIGN KEY (`storage_type_id`) REFERENCES `measurement_units` (`id`),
